const formatRut=v=>{let c=v.replace(/[^0-9kK]/g,"").slice(0,9);if(c.length<=1)return c;return c.slice(0,-1).replace(/\B(?=(\d{3})+(?!\d))/g,".")+"-"+c.slice(-1)};
const genId=()=>Math.random().toString(36).substr(2,9);
const fmtDate=d=>new Date(d).toLocaleDateString("es-CL",{day:"2-digit",month:"short",year:"numeric",hour:"2-digit",minute:"2-digit"});
const SK="fen-v3";

function genAllDates(){
  const all={};
  CURSOS_DEF.forEach(curso=>{
    const d=new Date(SEMANA_INICIO);
    while(d<=SEMESTRE_FIN){
      if(curso.dias.includes(d.getDay())){
        const y=d.getFullYear(),m=String(d.getMonth()+1).padStart(2,"0"),dd=String(d.getDate()).padStart(2,"0");
        const fechaStr=y+"-"+m+"-"+dd;
        const key=curso.id+"_"+fechaStr;
        const excluida=FECHAS_EXCLUIDAS.includes(fechaStr)||FECHAS_EXCLUIDAS.includes(key);
        if(!excluida){
          all[key]={key,cursoId:curso.id,fecha:new Date(d),fechaStr,
            label:DN[d.getDay()]+" "+d.getDate()+" de "+MN[d.getMonth()],
            labelShort:DN[d.getDay()].slice(0,3)+" "+d.getDate()+"/"+(d.getMonth()+1),
            cuposTotal:curso.cuposPorFecha,cuposDisponibles:curso.cuposPorFecha};
        }
      }
      d.setDate(d.getDate()+1);
    }
  });
  return all;
}

